DROP TABLE IF EXISTS `caipiao_fuddetail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_fuddetail` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `trano` char(20) NOT NULL COMMENT 'mã phiếu',
  `uid` int(11) NOT NULL COMMENT 'ID hội viên',
  `username` char(30) NOT NULL COMMENT 'hội viêntên đăng nhập',
  `type` char(30) NOT NULL COMMENT 'order cancel reward commissionhoàn cược activitykhuyến mãi transfer Platformnhà cung cấp backwaterhoàn trả cược backpointhoàn cược rollback editcommissionphí giao dịch editrechargenạp tiền editwithdrawrút tiền editactivitykhuyến mãi downrechargeđại lý tuyến dướinạp tiền upwithdrawđại lý cấp trênrút tiền withdraw Failurerút tiềnthất bại',
  `typename` varchar(60) NOT NULL COMMENT 'loạitên',
  `amount` decimal(14,2) NOT NULL COMMENT 'số tiền',
  `amountbefor` decimal(14,2) NOT NULL COMMENT 'số tiền',
  `amountafter` decimal(14,2) NOT NULL COMMENT 'số tiền',
  `oddtime` int(11) NOT NULL COMMENT 'thời gian',
  `remark` varchar(180) NOT NULL COMMENT 'ghi chú',
  PRIMARY KEY (`id`),
  KEY `uid` (`uid`),
  KEY `type` (`type`),
  KEY `trano` (`trano`),
  KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=11891 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='账户明细';
/*!40101 SET character_set_client = @saved_cs_client */;

